<!DOCTYPE html>
<html>
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<title>Falling Sand Sandbox</title>
<style>
  * {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
  }

  body {
    background: #1a1a1a;
    color: #fff;
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    min-height: 100vh;
    padding: 20px;
    gap: 20px;
  }

  h1 {
    font-size: 2rem;
    font-weight: 300;
    letter-spacing: 1px;
  }

  #sand {
    border: 2px solid #444;
    background: #000;
    cursor: crosshair;
    display: block;
    image-rendering: pixelated;
    box-shadow: 0 8px 32px rgba(0, 0, 0, 0.5);
  }

  .controls {
    display: flex;
    gap: 12px;
    flex-wrap: wrap;
    justify-content: center;
    max-width: 650px;
  }

  button {
    padding: 10px 18px;
    border: none;
    border-radius: 2px;
    font-size: 13px;
    font-weight: 500;
    cursor: pointer;
    transition: all 0.2s ease;
    text-transform: uppercase;
    letter-spacing: 0.5px;
  }

  button:hover:not(.active) {
    transform: translateY(-2px);
    box-shadow: 0 4px 8px rgba(0,0,0,0.3);
  }

  button:active {
    transform: translateY(0);
  }

  #mat-sand {
    background: #d4a574;
    color: #000;
  }

  #mat-water {
    background: #4a90e2;
    color: #fff;
  }

  #mat-wall {
    background: #666;
    color: #fff;
  }

  #mat-acid {
    background: #7cfc00;
    color: #000;
  }

  #mat-empty {
    background: #333;
    color: #fff;
  }

  #clear {
    background: #e74c3c;
    color: #fff;
    margin-left: 20px;
  }

  button.active {
    box-shadow: 0 0 0 3px rgba(255, 255, 255, 0.8), 0 4px 12px rgba(0,0,0,0.4);
  }
</style>
</head>
<body>

<h1>Falling Sand Sandbox</h1>

<canvas id="sand" width="400" height="400"></canvas>

<div class="controls">
  <button id="mat-sand">Sand</button>
  <button id="mat-water">Water</button>
  <button id="mat-wall">Wall</button>
  <button id="mat-acid">Acid</button>
  <button id="mat-empty">Erase</button>
  <button id="clear">Clear All</button>
</div>

<script>
const CELL_SIZE = 4;
const GRID_W = 100;
const GRID_H = 100;

const MATERIALS = {
  empty: 0,
  sand: 1,
  water: 2,
  wall: 3,
  acid: 4
};

const MATERIAL_NAMES = ['empty', 'sand', 'water', 'wall', 'acid'];
const COLORS = {
  empty: '#000000',
  sand: '#d4a574',
  water: '#4a90e2',
  wall: '#666666',
  acid: '#7cfc00'
};

class Simulator {
  constructor(w, h) {
    this.w = w;
    this.h = h;
    this.grid = new Uint8Array(w * h);
    this.newGrid = new Uint8Array(w * h);
  }

  get(x, y) {
    if (x < 0 || x >= this.w || y < 0 || y >= this.h) return 'empty';
    return MATERIAL_NAMES[this.grid[y * this.w + x]];
  }

  set(x, y, material) {
    if (x < 0 || x >= this.w || y < 0 || y >= this.h) return;
    this.grid[y * this.w + x] = MATERIALS[material] || 0;
  }

  clear() {
    this.grid.fill(0);
  }

  tick(n = 1) {
    for (let step = 0; step < n; step++) {
      this.newGrid.set(this.grid);
      this.modified = new Set();

      for (let y = this.h - 1; y >= 0; y--) {
        for (let x = 0; x < this.w; x++) {
          const mat = this.grid[y * this.w + x];

          if (mat === MATERIALS.empty || mat === MATERIALS.wall) continue;

          if (mat === MATERIALS.sand) {
            this._tickSand(x, y);
          } else if (mat === MATERIALS.water) {
            this._tickWater(x, y);
          } else if (mat === MATERIALS.acid) {
            this._tickAcid(x, y);
          }
        }
      }

      this.grid.set(this.newGrid);
    }
  }

  _canSet(x, y) {
    if (x < 0 || x >= this.w || y < 0 || y >= this.h) return false;
    const key = y * this.w + x;
    return !this.modified.has(key);
  }

  _set(x, y, mat) {
    if (!this._canSet(x, y)) return false;
    const key = y * this.w + x;
    this.newGrid[key] = mat;
    this.modified.add(key);
    return true;
  }

  _tickSand(x, y) {
    const belowMat = y + 1 < this.h ? this.grid[(y + 1) * this.w + x] : MATERIALS.wall;

    if (belowMat === MATERIALS.empty) {
      if (this._set(x, y + 1, MATERIALS.sand)) {
        this._set(x, y, MATERIALS.empty);
      }
      return;
    }

    if (belowMat === MATERIALS.water || belowMat === MATERIALS.acid) {
      if (this._set(x, y + 1, MATERIALS.sand)) {
        this._set(x, y, belowMat);
      }
      return;
    }

    const dirs = Math.random() < 0.5 ? [-1, 1] : [1, -1];
    for (const dx of dirs) {
      const nx = x + dx;
      if (nx >= 0 && nx < this.w) {
        const diagMat = y + 1 < this.h ? this.grid[(y + 1) * this.w + nx] : MATERIALS.wall;

        if (diagMat === MATERIALS.empty) {
          if (this._set(nx, y + 1, MATERIALS.sand)) {
            this._set(x, y, MATERIALS.empty);
          }
          return;
        }
      }
    }
  }

  _tickWater(x, y) {
    const belowMat = y + 1 < this.h ? this.grid[(y + 1) * this.w + x] : MATERIALS.wall;

    if (belowMat === MATERIALS.empty) {
      if (this._set(x, y + 1, MATERIALS.water)) {
        this._set(x, y, MATERIALS.empty);
      }
      return;
    }

    const dirs = Math.random() < 0.5 ? [-1, 1] : [1, -1];
    for (const dx of dirs) {
      const nx = x + dx;
      if (nx >= 0 && nx < this.w) {
        const sideMat = this.grid[y * this.w + nx];
        if (sideMat === MATERIALS.empty) {
          if (this._set(nx, y, MATERIALS.water)) {
            this._set(x, y, MATERIALS.empty);
          }
          return;
        }
      }
    }
  }

  _tickAcid(x, y) {
    const belowMat = y + 1 < this.h ? this.grid[(y + 1) * this.w + x] : MATERIALS.wall;

    if (belowMat === MATERIALS.empty) {
      if (this._set(x, y + 1, MATERIALS.acid)) {
        this._set(x, y, MATERIALS.empty);
      }
      return;
    }

    if (belowMat === MATERIALS.sand || belowMat === MATERIALS.wall) {
      if (this._set(x, y + 1, MATERIALS.acid)) {
        this._set(x, y, MATERIALS.empty);
      }
      return;
    }

    if (belowMat === MATERIALS.water) {
      if (this._set(x, y + 1, MATERIALS.acid)) {
        this._set(x, y, MATERIALS.water);
      }
      return;
    }

    const dirs = Math.random() < 0.5 ? [-1, 1] : [1, -1];
    for (const dx of dirs) {
      const nx = x + dx;
      if (nx >= 0 && nx < this.w) {
        const sideMat = this.grid[y * this.w + nx];
        if (sideMat === MATERIALS.empty) {
          if (this._set(nx, y, MATERIALS.acid)) {
            this._set(x, y, MATERIALS.empty);
          }
          return;
        }
        if (sideMat === MATERIALS.sand || sideMat === MATERIALS.wall) {
          if (this._set(nx, y, MATERIALS.acid)) {
            this._set(x, y, MATERIALS.empty);
          }
          return;
        }
      }
    }
  }
}

const sim = new Simulator(GRID_W, GRID_H);
window.sim = {
  w: GRID_W,
  h: GRID_H,
  tick: (n) => sim.tick(n),
  get: (x, y) => sim.get(x, y),
  set: (x, y, material) => sim.set(x, y, material),
  clear: () => sim.clear()
};

const canvas = document.getElementById('sand');
const ctx = canvas.getContext('2d');
canvas.width = GRID_W * CELL_SIZE;
canvas.height = GRID_H * CELL_SIZE;

let selectedMaterial = 'sand';
let isDrawing = false;

document.getElementById('mat-sand').addEventListener('click', () => {
  selectedMaterial = 'sand';
  updateButtonStates();
});
document.getElementById('mat-water').addEventListener('click', () => {
  selectedMaterial = 'water';
  updateButtonStates();
});
document.getElementById('mat-wall').addEventListener('click', () => {
  selectedMaterial = 'wall';
  updateButtonStates();
});
document.getElementById('mat-acid').addEventListener('click', () => {
  selectedMaterial = 'acid';
  updateButtonStates();
});
document.getElementById('mat-empty').addEventListener('click', () => {
  selectedMaterial = 'empty';
  updateButtonStates();
});

document.getElementById('clear').addEventListener('click', () => {
  sim.clear();
});

function updateButtonStates() {
  document.querySelectorAll('.controls button').forEach(btn => {
    btn.classList.remove('active');
  });

  const matId = {
    sand: 'mat-sand',
    water: 'mat-water',
    wall: 'mat-wall',
    acid: 'mat-acid',
    empty: 'mat-empty'
  }[selectedMaterial];

  if (matId) {
    document.getElementById(matId).classList.add('active');
  }
}

function paintCell(x, y) {
  const cellX = Math.floor(x / CELL_SIZE);
  const cellY = Math.floor(y / CELL_SIZE);
  if (cellX >= 0 && cellX < GRID_W && cellY >= 0 && cellY < GRID_H) {
    sim.set(cellX, cellY, selectedMaterial);
  }
}

canvas.addEventListener('mousedown', (e) => {
  isDrawing = true;
  const rect = canvas.getBoundingClientRect();
  paintCell(e.clientX - rect.left, e.clientY - rect.top);
});

canvas.addEventListener('mousemove', (e) => {
  if (!isDrawing) return;
  const rect = canvas.getBoundingClientRect();
  paintCell(e.clientX - rect.left, e.clientY - rect.top);
});

canvas.addEventListener('mouseup', () => {
  isDrawing = false;
});

canvas.addEventListener('mouseleave', () => {
  isDrawing = false;
});

function render() {
  ctx.fillStyle = '#000000';
  ctx.fillRect(0, 0, canvas.width, canvas.height);

  for (let y = 0; y < GRID_H; y++) {
    for (let x = 0; x < GRID_W; x++) {
      const mat = sim.get(x, y);
      if (mat !== 'empty') {
        ctx.fillStyle = COLORS[mat];
        ctx.fillRect(x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE);
      }
    }
  }
}

let lastTick = Date.now();
function animate() {
  const now = Date.now();
  const elapsed = now - lastTick;

  if (elapsed > 30) {
    sim.tick(1);
    lastTick = now;
  }

  render();
  requestAnimationFrame(animate);
}

updateButtonStates();
animate();
</script>

</body>
</html>
